### Network plot


::: {.cell}

```{.r .cell-code}
network_matchups <- games_fbs_teams_final |>
  dplyr::filter(
    (conference %in% power_conferences | team == "Notre Dame"),
    (opponentConference %in% power_conferences | opponent == "Notre Dame"),
    !conferenceGame, # Non-conference only
    opponentClassification == "fbs" # FBS opponents only
  ) |>
  dplyr::select(team, conference, opponent, opponentConference, week, gameDate)


edges_power <- network_matchups |>
  dplyr::select(from = team, to = opponent) |>
  dplyr::distinct()

nodes_power <- tibble::tibble(
  name = unique(c(edges_power$from, edges_power$to))
) |>
  dplyr::left_join(
    games_fbs_teams_final |>
      dplyr::select(team, conference) |>
      dplyr::distinct() |>
      dplyr::rename(name = team),
    by = "name"
  ) |>
  dplyr::mutate(
    conference = dplyr::if_else(name == "Notre Dame", "Independent", conference)
  )

graph_power <- tidygraph::tbl_graph(
  nodes = nodes_power,
  edges = edges_power,
  directed = FALSE
)

node_positions <- graph_power |>
  ggraph::create_layout(layout = 'stress') |>
  dplyr::select(x, y, name)

nodes_with_positions <- dplyr::left_join(
  nodes_power,
  node_positions,
  by = "name"
)


power_network_plot <- graph_power |>
  ggraph::ggraph(layout = 'fr') + # Fruchterman-Reingold layout: https://github.com/gephi/gephi/wiki/Fruchterman-Reingold
  ggraph::geom_edge_link(
    ggplot2::aes(alpha = 0.2),
    color = 'gray40',
    show.legend = FALSE
  ) +
  ggraph::geom_node_point(
    ggplot2::aes(color = conference),
    size = 12,
    alpha = 0.5
  ) +
  ggraph::geom_node_text(
    ggplot2::aes(label = name),
    size = 2.5,
    fontface = "bold",
    color = "black",
    repel = TRUE
  ) +
  ggplot2::scale_color_manual(
    values = c(
      'SEC' = '#d4a017',
      'ACC' = '#2e5194',
      'Big Ten' = '#c0392b',
      'Big 12' = '#1e7d32',
      'Independent' = '#5d6d7e'
    ),
    labels = c(
      'SEC' = 'SEC',
      'ACC' = 'ACC', 
      'Big Ten' = 'Big Ten',
      'Big 12' = 'Big 12',
      'Independent' = 'Notre Dame'
  ),
    name = ''
  ) +
  ggplot2::theme_minimal() +
  ggplot2::labs(
    title = "Network of Opponents Across 'Power' Conferences & Notre Dame",
    subtitle = "Each connection represents a scheduled non-conference game during the 2025 college football regular season.<br><br>Arizona and Kansas State play a 'non-conference' game, but both are members of the Big 12 and the game is not surfaced on the chart.",
    caption = "Data via collegefootballdata.com | Viz by Chris at Bless your Chart"
  ) +
  ggplot2::theme(
    plot.title = ggplot2::element_text(hjust = 0.5, size = 12, face = 'bold'),
    plot.subtitle = ggtext::element_markdown(hjust = 0.5, size = 9),
    plot.caption = ggplot2::element_text(size = 8),
    legend.position = "top",
    legend.title = ggplot2::element_text(size = 10),
    legend.text = ggplot2::element_text(size = 9),
    panel.grid = ggplot2::element_blank(),
    axis.text = ggplot2::element_blank(),
    axis.title = ggplot2::element_blank()
  ) +
  ggplot2::guides(
    color = ggplot2::guide_legend(override.aes = list(alpha = 0.5, size = 4))
  )

ggplot2::ggsave(
  "power_network_plot.png",
  power_network_plot,
  w = 10.5,
  h = 8.5,
  bg = "white",
  dpi = 600,
  type = 'cairo'
)

